var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…잡았어.","JPN":"……倒した。","ENG":"…We got it.","TWN":"…結束了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…저 커다란 걸 단숨에 베었다고?","JPN":"……あのデカいやつを、一撃で斬った？","ENG":"…He cut that whole thing down in one strike?","TWN":"…一刀就斬斷那麼巨大的東西？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"방금 네 사부가 무슨 짓을 한 거지?","JPN":"お前の師匠はいったい何をしたんだ？","ENG":"What did your Master just do?","TWN":"你師父剛才做了什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"바보짓.","JPN":"バカなこと。","ENG":"Something stupid.","TWN":"愚蠢的行為。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 바보… 또 쓰러지겠네.","JPN":"あのバカ……また倒れるよ。","ENG":"That idiot… He's gonna collapse again.","TWN":"那個笨蛋…又要暈倒了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쿨럭-!","JPN":"ゲホッ……！","ENG":"*Cough!*","TWN":"咳—！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_WATER_03"},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"또, 칼에 피를 먹였구나.","JPN":"また、刃に血を飲ませたのね。","ENG":"Once again, you've fed the sword blood.","TWN":"你，又用血去餵那把劍了嗎。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그 방식이 몸에 주는 부담을 알고 있을 텐데, 충동에 휘둘려 힘을 쓴 거야?","JPN":"その使い方が体に負担をかけるって分かっているくせに、衝動に任せて力を使ったの？","ENG":"You know it's killing you. And yet you still let the impulse take over?","TWN":"你明知道對身體不好，卻還是因為衝動而使用這股力量？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…담판을 지어야만 했네.","JPN":"……けじめをつけるべきだった。","ENG":"…I had to end it.","TWN":"…我必須當機立斷。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"후회가 남지 않도록.","JPN":"後悔が残らぬように。","ENG":"So there'd be no regrets.","TWN":"不留下任何遺憾。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"후회라면 이미 오래 전에 했잖아.","JPN":"後悔ならとっくの昔にしてるでしょう。","ENG":"Regret? You've already drowned in it long ago.","TWN":"你早就經歷過遺憾。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"이제사 녀석에게 복수한들, 죽은 가족이 돌아오진 않아.","JPN":"今更やつに復讐したところで、死んだ家族が戻ることはないわ。","ENG":"Even if you got revenge now, your family wouldn't come back.","TWN":"就算現在向那傢伙復仇，死去的家人也不會回來。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"You're right.","TWN":"對。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"뻗어도 쥐지 못할… 뜬구름인 게지.","JPN":"手を伸ばしても掴むことのできぬ……浮き雲のようなものだ。","ENG":"It's like grasping… sand that slips through your fingers.","TWN":"就算伸手去抓，也抓不到…像浮雲一般。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"그 누구도 지나간 일을 돌이키지 못해.","JPN":"過ぎたことは誰にも取り戻せないわ。","ENG":"No one can undo what's already passed.","TWN":"沒有任何人，能讓過去的事情重來。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"하지만 당신은 다르잖아. 특별한 피를 가졌으니까.","JPN":"でもあなたは違う。特別な血を持っているもの。","ENG":"But you're different. You carry a special bloodline.","TWN":"但你不同。你擁有特殊的血。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"그 특별함을 고작 복수 따위에 허비하지 마.","JPN":"あなたの特別さを、復讐ごときのために無駄遣いしないで。","ENG":"Don't waste that gift on something as petty as revenge.","TWN":"不要將那份特殊，浪費在區區復仇上。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그래. 허투루 써서는 안 되겠지. 이 힘을 쏟아야 할 데는 이미 정해 두었으니.","JPN":"……そうだな、無駄遣いしてはならん。この力をどこに注ぎ込むべきかは、すでに決まっているゆえ。","ENG":"…You're right. This power can't be wasted. I already know where it needs to go.","TWN":"…說得對。不該隨便使用。我早已決定好，這份力量該用在哪裡。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"시간을 거슬러… 그 먹빛 화근을 뿌리 뽑을 때까지.","JPN":"時を遡り……あの墨色の禍根を絶つまでは。","ENG":"Back through time… Until I tear out the root of that ink-black disaster.","TWN":"逆轉時間…直到將那墨雨的禍根連根拔除。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"병원으로 데려온 건 잘한 결정이다.","JPN":"病院につれてきて正解だったな。","ENG":"You made the right call bringing him to the hospital.","TWN":"帶他來醫院是個正確的決定。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"의사에게 물어보니, 집에서 하는 간병치레만으론 회복이 어려웠을 거라더군.","JPN":"医者に聞いたところ、家での手当だけで回復するのは難しい状態だったようだ。","ENG":"The doctor said he wouldn't have recovered properly with just home care.","TWN":"醫生說，只靠家裡的照護很難康復。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"…Yeah.","TWN":"…嗯。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"네 사부는 그 검을 사용할 때마다 의식을 잃었다고 했었지.","JPN":"お前の師匠は、あの剣を使うたびに気を失ったと言ったな。","ENG":"You mentioned your master always passed out when using that sword.","TWN":"你說他每次使用那把劍都會失去意識對吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그런데 이번엔 의식을 잃는 정도가 아니라 피를 한 말 토하며 쓰러졌어. 숨 쉬는 걸 확인하기 전까진 죽었다고 생각했고.","JPN":"しかし今回は気を失う程度では済まず、かなりの血を吐いて倒れた。息をしていることを確認するまでは、てっきり死んだと思った。","ENG":"But this time it wasn't just passing out. He coughed up so much blood, I thought he was dead.","TWN":"但這次，不只是失去意識，而是吐血後倒下。在確認他還有呼吸之前，我以為他死了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 칼은 역시 버리는 게 좋겠어.","JPN":"あの剣はやっぱり捨てたほうがいいよね。","ENG":"We've gotta get rid of that sword.","TWN":"這把劍還是丟掉比較好。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그럼 하루 온종일 찾으러 다니겠지. 연화를 이기려면 그게 필요할 테니.","JPN":"そうしたら一日中探し回るだろう。レンカに勝つためにはそれが必要だから。","ENG":"Then he'd probably spend all day trying to find it again. He needs it if he ever wants to beat Yeonhwa.","TWN":"那他會花一整天去尋找。為了打贏蓮華，他需要那把刀。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그렇게 흥분한 모습은 처음 봤어.","JPN":"あんなに興奮した姿、初めて見たよ。","ENG":"That was the first time I saw him so worked up.","TWN":"我第一次看到他那麼激動。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부는 나보다 훨씬 똑똑한 사람인데… 왜 그렇게까지 무리하면서 그 침식체를 잡고 싶어한 걸까?","JPN":"師匠は私よりずっと賢い人なのに……なんであそこまで無理して、あの侵食体を倒そうとしたのかな。","ENG":"He's way smarter than me… So why would he push himself that far just to take that thing down?","TWN":"師父是個比我聰明的人…為什麼他會那麼拼命地想要抓住那個侵蝕體？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"여긴 서생이 어릴 적에 떠난 고향이라고 했었지.","JPN":"ここはショウの故郷で、彼は幼い頃ここを離れたと言ったな。","ENG":"This is the hometown Seosaeng left when he was a child, right?","TWN":"你說過，這裡是書生小時候離開的故鄉。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 뒤의 행적이 관리국으로 향했다면, 분명 좋은 이유로 떠난 건 아닐 거다.","JPN":"その後管理局に入ったということは、やつがここを離れたきっかけはあまりいいことじゃないはずだ。","ENG":"If his path after that led to the Administration, he probably didn't leave for a happy reason.","TWN":"如果他後來的行蹤是去了管理局，那原因肯定不會是好的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이 땅에 먹비가 침범해 터전이 망가진 것도 그 시기 즈음이라 들었으니까.","JPN":"墨雨がこの地を襲い、人々の生活が破壊されたのもその頃だと聞いている。","ENG":"From what I heard, the Ink Rain hit around the same time and destroyed everything here.","TWN":"我聽說，這片土地被墨雨入侵，家園被破壞，也是在那段時期。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼…","JPN":"じゃあ……","ENG":"Then…","TWN":"那麼…"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부는 그 침식체를 알고 있던 걸까?","JPN":"師匠はあの侵食体のことを知っていたのかな。","ENG":"Did he already know that C.O.?","TWN":"師父是不是認識那個侵蝕體？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거에 마주했던 녀석과 같거나… 적어도 닮은 개체였겠지.","JPN":"過去に出会ったやつか……少なくとも、酷似した個体だったんだろう。","ENG":"It was probably the same one he met in the past… Or at least something just like it.","TWN":"或許和過去他遇到的那傢伙是同一個…或者至少是相似的個體吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"맞설 수 없는 상대로부터 도망칠 때의 무력감은 좀처럼 잊기 힘들어. 그 일로 소중한 사람을 잃었다면 더더욱 그럴 테고.","JPN":"立ち向かえない相手から逃げ出す時の無力感というものは、なかなか拭いきれないものだ。まして、そのことが原因で大事な人を失っているならなおさらな。","ENG":"You never forget the powerlessness of running from something you can't beat. Especially if it cost you someone you loved.","TWN":"面對無法抗衡的對手時，那種無力感是很難忘懷的。如果因為那件事失去重要的人，那更是如此。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"사부한테는…","JPN":"師匠には……","ENG":"Master has…","TWN":"師父他…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_4"},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"나한테 없는 과거가 있다.","JPN":"私にはない過去がある。","ENG":"a past that I don't.","TWN":"擁有我沒有的過去。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_5"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"난 지난 과거보다 오늘이 더 소중하다는 것을 당연한 것처럼 여겼는데…","JPN":"過ぎたことより今日のほうが大事。私にとってはそれが当たり前だった。けど……","ENG":"I always thought it was obvious that today matters more than yesterday…","TWN":"我理所當然地認為，今天比過去更重要…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_6"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"어쩌면 그 사람에겐 그게 전부가 아닐 지도 모른다는… 그런 생각이 들었다.","JPN":"もしかすると、彼にとってはそれがすべてじゃないのかもしれないと……そう思った。","ENG":"But maybe for him, it's… not that simple.","TWN":"但我突然覺得，或許對那個人來說，那並非全部…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_7"}]`);export{e as default};